const prev = $('Processar Payload').first().json;
const oc = $input.item.json;

return {
  url: `https://graph.facebook.com/v21.0/${prev.phoneNumberId}/messages`,
  body: JSON.stringify({
    messaging_product: 'whatsapp',
    to: prev.phone,
    type: 'interactive',
    interactive: {
      type: 'button',
      body: {
        text: `✅ *Ocorrência registrada!*\n\n📋 Protocolo: *${oc.protocolo}*\n🏷️ Categoria: ${oc.categoriaNome || 'Classificando...'}\n⚠️ Prioridade: ${oc.scorePrioridade}\n\nObrigado por contribuir! 🏙️`
      },
      action: {
        buttons: [
          { type: 'reply', reply: { id: `status_${oc.protocolo}`, title: '📋 Ver status' } },
          { type: 'reply', reply: { id: 'novo_reporte', title: '➕ Novo reporte' } }
        ]
      }
    }
  })
};

const prev = $('Processar Payload').first().json;
const resp = $input.item.json;

let text = '';
if (resp.protocolo) {
  const emojis = { RECEBIDA:'📥', EM_ANALISE:'🔍', VALIDADA:'✅', EM_RESOLUCAO:'🔧', RESOLVIDA:'🎉', ARQUIVADA:'📦', REJEITADA:'❌' };
  const e = emojis[resp.status] || '📋';
  const s = (resp.status||'').replace(/_/g,' ');
  const d = resp.dataRegistro ? resp.dataRegistro.substring(0,10) : '—';
  const desc = resp.descricao?.length > 80 ? resp.descricao.substring(0,80)+'...' : (resp.descricao||'—');
  text = `🔍 *Status do Protocolo ${resp.protocolo}*\n\n${e} Status: *${s}*\n🏷️ Categoria: ${resp.categoriaNome||'—'}\n📝 ${desc}\n📅 Registrado: ${d}`;
} else {
  text = `⚠️ Protocolo *${prev.text}* não encontrado. Verifique o número (formato: RPT-2026-00001).`;
}

return {
  url: `https://graph.facebook.com/v21.0/${prev.phoneNumberId}/messages`,
  body: JSON.stringify({
    messaging_product: 'whatsapp',
    to: prev.phone,
    type: 'text',
    text: { body: text }
  })
};
